/// A concurrent hash map built on top of sharded ConcurrentCells.
pub struct ConcurrentMap<K, V> {
    shards: Vec<ConcurrentCell<Vec<(K, V)>>>,
    shard_count: usize,
}

unsafe impl<K: Send, V: Send> Send for ConcurrentMap<K, V> {}
unsafe impl<K: Send, V: Send> Sync for ConcurrentMap<K, V> {}

impl<K, V> ConcurrentMap<K, V>
where
    K: std::hash::Hash + Eq + Clone,
    V: Clone,
{
    pub fn new() -> Self {
        Self::with_shard_count(16)
    }

    pub fn with_shard_count(count: usize) -> Self {
        let mut shards = Vec::with_capacity(count);
        for _ in 0..count {
            shards.push(ConcurrentCell::new(Vec::new()));
        }
        ConcurrentMap {
            shards,
            shard_count: count,
        }
    }

    fn shard_index(&self, key: &K) -> usize {
        use std::hash::{Hash, Hasher};
        let mut hasher = std::collections::hash_map::DefaultHasher::new();
        key.hash(&mut hasher);
        (hasher.finish() as usize) % self.shard_count
    }

    pub fn insert(&self, key: K, value: V) -> Option<V> {
        let idx = self.shard_index(&key);
        let mut guard = self.shards[idx].write();
        for entry in guard.iter_mut() {
            if entry.0 == key {
                let old = std::mem::replace(&mut entry.1, value);
                return Some(old);
            }
        }
        guard.push((key, value));
        None
    }

    pub fn get(&self, key: &K) -> Option<V> {
        let idx = self.shard_index(key);
        let guard = self.shards[idx].read();
        for entry in guard.iter() {
            if entry.0 == *key {
                return Some(entry.1.clone());
            }
        }
        None
    }

    pub fn remove(&self, key: &K) -> Option<V> {
        let idx = self.shard_index(key);
        let mut guard = self.shards[idx].write();
        if let Some(pos) = guard.iter().position(|entry| entry.0 == *key) {
            let (_, v) = guard.swap_remove(pos);
            Some(v)
        } else {
            None
        }
    }

    pub fn contains_key(&self, key: &K) -> bool {
        let idx = self.shard_index(key);
        let guard = self.shards[idx].read();
        guard.iter().any(|entry| entry.0 == *key)
    }
}

