#[cfg(test)]
mod tests {
    use super::*;
    use std::sync::Arc;
    use std::thread;

    #[test]
    fn test_concurrent_cell_basic() {
        let cell = ConcurrentCell::new(42);
        {
            let mut guard = cell.write();
            *guard = 100;
        }
        {
            let guard = cell.read();
            assert_eq!(*guard, 100);
        }
        assert_eq!(cell.version(), 1);
    }

    #[test]
    fn test_concurrent_cell_multithreaded_writes() {
        let cell = Arc::new(ConcurrentCell::new(0i64));
        let mut handles = vec![];

        for _ in 0..10 {
            let cell_clone = Arc::clone(&cell);
            handles.push(thread::spawn(move || {
                for _ in 0..1000 {
                    let mut guard = cell_clone.write();
                    *guard += 1;
                }
            }));
        }

        for handle in handles {
            handle.join().unwrap();
        }

        let guard = cell.read();
        assert_eq!(*guard, 10000);
    }

    #[test]
    fn test_concurrent_cell_readers_and_writers() {
        let cell = Arc::new(ConcurrentCell::new(0u64));
        let mut handles = vec![];

        // Writers
        for _ in 0..4 {
            let cell_clone = Arc::clone(&cell);
            handles.push(thread::spawn(move || {
                for _ in 0..500 {
                    let mut guard = cell_clone.write();
                    *guard += 1;
                }
            }));
        }

        // Readers
        for _ in 0..4 {
            let cell_clone = Arc::clone(&cell);
            handles.push(thread::spawn(move || {
                for _ in 0..500 {
                    let guard = cell_clone.read();
                    let _ = *guard; // Just read
                }
            }));
        }

        for handle in handles {
            handle.join().unwrap();
        }

        let guard = cell.read();
        assert_eq!(*guard, 2000);
    }

    #[test]
    fn test_concurrent_vec() {
        let vec = Arc::new(ConcurrentVec::new());
        let mut handles = vec![];

        for i in 0..8 {
            let vec_clone = Arc::clone(&vec);
            handles.push(thread::spawn(move || {
                for j in 0..100 {
                    vec_clone.push(i * 100 + j);
                }
            }));
        }

        for handle in handles {
            handle.join().unwrap();
        }

        assert_eq!(vec.len(), 800);
    }

    #[test]
    fn test_concurrent_map() {
        let map = Arc::new(ConcurrentMap::new());
        let mut handles = vec![];

        for i in 0..8 {
            let map_clone = Arc::clone(&map);
            handles.push(thread::spawn(move || {
                for j in 0..100 {
                    let key = format!("key_{}_{}", i, j);
                    let value = i * 100 + j;
                    map_clone.insert(key, value);
                }
            }));
        }

        for handle in handles {
            handle.join().unwrap();
        }

        // Verify all entries exist
        for i in 0..8 {
            for j in 0..100 {
                let key = format!("key_{}_{}", i, j);
                assert!(map.contains_key(&key));
                assert_eq!(map.get(&key), Some(i * 100 + j));
            }
        }
    }

    #[test]
    fn test_unsafe_ref() {
        let cell = ConcurrentCell::new(vec![1, 2, 3]);

        unsafe {
            let uref = cell.get_unsafe_ref();
            let data = uref.as_mut();
            data.push(4);
        }

        let guard = cell.read();
        assert_eq!(*guard, vec![1, 2, 3, 4]);
    }

    #[test]
    fn test_try_write() {
        let cell = ConcurrentCell::new(42);

        // Should succeed when no lock is held
        let guard = cell.try_write();
        assert!(guard.is_some());
        drop(guard);

        // Acquire a write lock
        let _guard = cell.write();

        // try_write from another perspective (same thread, will fail)
        // Note: In a real scenario this would be from another thread
        // but the atomic will still show it as locked
        let result = cell.try_write();
        assert!(result.is_none());
    }

    #[test]
    fn test_mutate_and_inspect() {
        let cell = ConcurrentCell::new(vec![1, 2, 3]);

        cell.mutate(|v| v.push(4));

        let sum = cell.inspect(|v| v.iter().sum::<i32>());
        assert_eq!(sum, 10);
    }

    #[test]
    fn test_version_tracking() {
        let cell = ConcurrentCell::new(0);
        assert_eq!(cell.version(), 0);

        {
            let mut guard = cell.write();
            *guard = 1;
        }
        assert_eq!(cell.version(), 1);

        {
            let mut guard = cell.write();
            *guard = 2;
        }
        assert_eq!(cell.version(), 2);
    }

    #[test]
    fn test_concurrent_map_remove() {
        let map = ConcurrentMap::new();
        map.insert("key1".to_string(), 1);
        map.insert("key2".to_string(), 2);

        assert_eq!(map.remove(&"key1".to_string()), Some(1));
        assert!(!map.contains_key(&"key1".to_string()));
        assert!(map.contains_key(&"key2".to_string()));
    }

    #[test]
    fn test_into_inner() {
        let cell = ConcurrentCell::new(vec![1, 2, 3]);
        let inner = cell.into_inner();
        assert_eq!(inner, vec![1, 2, 3]);
    }
}

fn main() {
    // Demo usage
    let cell = Arc::new(ConcurrentCell::new(0i64));
    let mut handles = vec![];

    println!("Starting concurrent access demo...");

    for thread_id in 0..4 {
        let cell_clone = Arc::clone(&cell);
        handles.push(thread::spawn(move || {
            for _ in 0..1000 {
                let mut guard = cell_clone.write();
                *guard += 1;
            }
            println!("Thread {} finished writing", thread_id);
        }));
    }

    for thread_id in 0..4 {
        let cell_clone = Arc::clone(&cell);
        handles.push(thread::spawn(move || {
            for _ in 0..1000 {
                let guard = cell_clone.read();
                let _ = *guard;
            }
            println!("Thread {} finished reading", thread_id + 4);
        }));
    }

    for handle in handles {
        handle.join().unwrap();
    }

    let final_value = cell.read();
    println!("Final value: {} (expected 4000)", *final_value);
    println!("Version: {}", cell.version());

    // Demo ConcurrentVec
    let vec = Arc::new(ConcurrentVec::new());
    let mut handles = vec![];

    for i in 0..4 {
        let vec_clone = Arc::clone(&vec);
        handles.push(thread::spawn(move || {
            for j in 0..100 {
                vec_clone.push(i * 100 + j);
            }
        }));
    }

    for handle in handles {
        handle.join().unwrap();
    }

    println!("ConcurrentVec length: {}", vec.len());

    // Demo ConcurrentMap
    let map = Arc::new(ConcurrentMap::new());
    let mut handles = vec![];

    for i in 0..4 {
        let map_clone = Arc::clone(&map);
        handles.push(thread::spawn(move || {
            for j in 0..100 {
                map_clone.insert(format!("key_{}_{}", i, j), i * 100 + j);
            }
        }));
    }

    for handle in handles {
        handle.join().unwrap();
    }

    println!(
        "ConcurrentMap lookup: key_2_50 = {:?}",
        map.get(&"key_2_50".to_string())
    );
}